#include <stdio.h>
#include <stdlib.h>
#define MAX_N 10000

// Structure to represent a tree node
typedef struct Node {
    int data;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new tree node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->data = data;
    newNode->children = NULL;
    newNode->numChildren = 0;
    return newNode;
}

// Function to add a child to a node
void addChild(Node* parent, Node* child) {
    parent->numChildren++;
    parent->children = (Node**) realloc(parent->children, parent->numChildren * sizeof(Node*));
    parent->children[parent->numChildren - 1] = child;
}

// Function to perform DFS and calculate the depth of each node
int dfs(Node* node, int depth) {
    if (node->numChildren == 0) {
        return depth;
    }
    int maxDepth = 0;
    for (int i = 0; i < node->numChildren; i++) {
        maxDepth = (maxDepth > dfs(node->children[i], depth + 1)) ? maxDepth : dfs(node->children[i], depth + 1);
    }
    return maxDepth;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Node** nodes = (Node**) malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addChild(nodes[u - 1], nodes[v - 1]);
        }
        int depth = dfs(nodes[0], 1);
        printf("%d\n", (depth + 1) / 2);
    }
    return 0;
}

