#include <iostream>
#include <vector>
using namespace std;

// Structure to represent a tree node
struct Node {
    int data;
    vector<Node*> children;
};

// Function to create a new tree node
Node* createNode(int data) {
    Node* newNode = new Node;
    newNode->data = data;
    return newNode;
}

// Function to add a child to a node
void addChild(Node* parent, Node* child) {
    parent->children.push_back(child);
}

// Function to perform DFS and calculate the depth of each node
int dfs(Node* node, int depth) {
    if (node->children.empty()) {
        return depth;
    }
    int maxDepth = 0;
    for (Node* child : node->children) {
        maxDepth = max(maxDepth, dfs(child, depth + 1));
    }
    return maxDepth;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        Node** nodes = new Node*[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            cin >> u >> v;
            addChild(nodes[u - 1], nodes[v - 1]);
        }
        int depth = dfs(nodes[0], 1);
        cout << (depth + 1) / 2 << endl;
    }
    return 0;
}

