import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    // Structure to represent a tree node
    static class Node {
        int data;
        ArrayList<Node> children;

        public Node(int data) {
            this.data = data;
            this.children = new ArrayList<>();
        }
    }

    // Function to add a child to a node
    public static void addChild(Node parent, Node child) {
        parent.children.add(child);
    }

    // Function to perform DFS and calculate the depth of each node
    public static int dfs(Node node, int depth) {
        if (node.children.isEmpty()) {
            return depth;
        }
        int maxDepth = 0;
        for (Node child : node.children) {
            maxDepth = Math.max(maxDepth, dfs(child, depth + 1));
        }
        return maxDepth;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                nodes[i] = new Node(i + 1);
            }
            for (int i = 0; i < N - 1; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                addChild(nodes[u - 1], nodes[v - 1]);
            }
            int depth = dfs(nodes[0], 1);
            System.out.println((depth + 1) / 2);
        }
    }
}

